const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
function map01ToPI(v) { return (v * 2 * Math.PI) - Math.PI;}

async function getSharedValue({
  baseUrl = "http://MacBook-Pro-de-olivier.local:3009",
  valueName = "value",
  sleepTime = "sleepTime",
} = {}) {
  await sleep(sleepTime)
  const url = `${baseUrl.replace(/\/+$/, "")}/apiR/${encodeURIComponent(valueName)}`;

  const r = await fetch(url, { method: "GET" });

  const data = await r.json().catch(() => ({}));
  if (!r.ok) throw new Error(data?.error || `HTTP ${r.status}`);

  return data?.[valueName];
}

const baseUrl = "http://MacBook-Pro-de-olivier.local:3009";
const valueName = "ShowImage";
const sleepTime = 200;
const got = await getSharedValue({ baseUrl, valueName ,sleepTime});
if (got==1){
game.actions.setShowImageSlideShow(true);
}
return got;

